fn solve(s: String, order: Vec<i64>, k: i64) -> i64 {
    let n = s.len();
    let mut stars = vec![false; n]; // Track which positions are replaced with '*'
    let mut total_valid = 0; // Total number of valid substrings

    // Precompute the number of valid substrings after each step
    for t in 0..n {
        let pos = order[t] as usize;
        stars[pos] = true; // Replace the character at pos with '*'

        // Count the number of valid substrings that include the current '*'
        // The number of valid substrings that include pos is (pos + 1) * (n - pos)
        let valid_substrings = (pos + 1) * (n - pos) as i64;
        total_valid += valid_substrings;

        // Check if total valid substrings is >= k
        if total_valid >= k {
            return t as i64;
        }
    }

    return -1; // If never reached, return -1
}
